1	/* sws.c -- Software Wrighter Script interpreter for COR24
2	 *
3	 * A Tcl-like command language for shell and editor scripting.
4	 * Compiled by tc24r (cross C compiler), runs on COR24 hardware or emulator.
5	 *
6	 * tc24r constraints: no structs, no malloc/free, no string library,
7	 * no varargs/printf, single translation unit, 24-bit int, 8-bit char.
8	 */
9	
10	/* ---- UART I/O (memory-mapped) ---- */
11	
12	#define UART_DATA   0xFF0100
13	#define UART_STATUS 0xFF0101
14	
15	void uart_putc(int ch) {
16	    int tries = 50000;
17	    while ((*(char *)UART_STATUS & 0x80) && tries > 0) {
18	        tries = tries - 1;
19	    }
20	    *(char *)UART_DATA = ch;
21	}
22	
23	int uart_getc() {
24	    while (!(*(char *)UART_STATUS & 0x01)) {}
25	    return *(char *)UART_DATA;
26	}
27	
28	void uart_puts(char *s) {
29	    while (*s) {
30	        uart_putc(*s);
31	        s = s + 1;
32	    }
33	}
34	
35	void uart_putint(int n) {
36	    if (n < 0) {
37	        uart_putc(45); /* '-' */
38	        n = 0 - n;
39	    }
40	    if (n == 0) {
41	        uart_putc(48); /* '0' */
42	        return;
43	    }
44	    char buf[12];
45	    int i = 0;
46	    while (n > 0) {
47	        buf[i] = 48 + n % 10;
48	        n = n / 10;
49	        i = i + 1;
50	    }
51	    while (i > 0) {
52	        i = i - 1;
53	        uart_putc(buf[i]);
54	    }
55	}
56	
57	void uart_newline() {
58	    uart_putc(10);
59	}
60	
61	/* ---- Static allocation limits ---- */
62	
63	#define MAX_LINE_LEN   512
64	#define MAX_TOKENS       32
65	#define MAX_TOKEN_LEN   128
66	#define MAX_VARS         64
67	#define MAX_VAR_NAME     32
68	#define MAX_VAR_VAL     128
69	#define MAX_NEST         64
70	#define MAX_FIELDS       16
71	
72	/* ---- String helpers ---- */
73	
74	int str_len(char *s) {
75	    int n = 0;
76	    while (s[n]) n = n + 1;
77	    return n;
78	}
79	
80	int str_eq(char *a, char *b) {
81	    int i = 0;
82	    while (a[i] && b[i]) {
83	        if (a[i] != b[i]) return 0;
84	        i = i + 1;
85	    }
86	    return a[i] == b[i];
87	}
88	
89	void str_copy(char *dst, char *src) {
90	    int i = 0;
91	    while (src[i]) {
92	        dst[i] = src[i];
93	        i = i + 1;
94	    }
95	    dst[i] = 0;
96	}
97	
98	int str_starts_with(char *s, char *prefix) {
99	    int i = 0;
100	    while (prefix[i]) {
101	        if (s[i] != prefix[i]) return 0;
102	        i = i + 1;
103	    }
104	    return 1;
105	}
106	
107	int str_to_int(char *s) {
108	    int n = 0;
109	    int neg = 0;
110	    int i = 0;
111	    if (s[0] == 45) { /* '-' */
112	        neg = 1;
113	        i = 1;
114	    }
115	    while (s[i] >= 48 && s[i] <= 57) { /* '0'-'9' */
116	        n = n * 10 + (s[i] - 48);
117	        i = i + 1;
118	    }
119	    if (neg) n = 0 - n;
120	    return n;
121	}
122	
123	void int_to_str(char *buf, int n) {
124	    if (n == 0) {
125	        buf[0] = 48;
126	        buf[1] = 0;
127	        return;
128	    }
129	    int neg = 0;
130	    if (n < 0) {
131	        neg = 1;
132	        n = 0 - n;
133	    }
134	    char tmp[12];
135	    int i = 0;
136	    while (n > 0) {
137	        tmp[i] = 48 + n % 10;
138	        n = n / 10;
139	        i = i + 1;
140	    }
141	    int j = 0;
142	    if (neg) {
143	        buf[0] = 45;
144	        j = 1;
145	    }
146	    while (i > 0) {
147	        i = i - 1;
148	        buf[j] = tmp[i];
149	        j = j + 1;
150	    }
151	    buf[j] = 0;
152	}
153	
154	/* ---- Tokenizer ---- */
155	
156	/* Token types */
157	#define TOK_WORD   0
158	#define TOK_QUOTED 1
159	#define TOK_BLOCK  2
160	
161	/* Flat buffer: token i starts at token_starts[i] in token_pool */
162	#define TOKEN_POOL_SIZE 2048
163	char token_pool[TOKEN_POOL_SIZE];
164	int  token_starts[MAX_TOKENS];
165	int  token_type[MAX_TOKENS];
166	int  token_count;
167	int  token_pool_used;
168	
169	/* Get pointer to token string */
170	char *token_str(int idx) {
171	    return token_pool + token_starts[idx];
172	}
173	
174	/* Append a char to the current token being built */
175	void tok_putc(int ch) {
176	    if (token_pool_used < TOKEN_POOL_SIZE - 1) {
177	        token_pool[token_pool_used] = ch;
178	        token_pool_used = token_pool_used + 1;
179	    }
180	}
181	
182	/* Terminate the current token */
183	void tok_end() {
184	    if (token_pool_used < TOKEN_POOL_SIZE) {
185	        token_pool[token_pool_used] = 0;
186	        token_pool_used = token_pool_used + 1;
187	    }
188	}
189	
190	/* tokenize_line: split a line into tokens.
191	 * Returns token count, or -1 on syntax error.
192	 */
193	int tokenize_line(char *line) {
194	    int i = 0;
195	    token_count = 0;
196	    token_pool_used = 0;
197	
198	    while (line[i]) {
199	        /* skip whitespace */
200	        while (line[i] == 32 || line[i] == 9)
201	            i = i + 1;
202	
203	        if (line[i] == 0) break;
204	
205	        /* comment — rest of line ignored */
206	        if (line[i] == 35) break;
207	
208	        if (token_count >= MAX_TOKENS) break;
209	
210	        if (line[i] == 34) { /* '"' — quoted string */
211	            token_starts[token_count] = token_pool_used;
212	            i = i + 1; /* skip opening quote */
213	            while (line[i] && line[i] != 34) {
214	                if (line[i] == 92 && line[i + 1]) { /* backslash escape */
215	                    i = i + 1;
216	                    if (line[i] == 110)
217	                        tok_putc(10); /* \n */
218	                    else if (line[i] == 116)
219	                        tok_putc(9); /* \t */
220	                    else
221	                        tok_putc(line[i]);
222	                    i = i + 1;
223	                } else {
224	                    tok_putc(line[i]);
225	                    i = i + 1;
226	                }
227	            }
228	            if (line[i] != 34) {
229	                uart_puts("error: unterminated quote");
230	                uart_newline();
231	                return -1;
232	            }
233	            i = i + 1; /* skip closing quote */
234	            tok_end();
235	            token_type[token_count] = TOK_QUOTED;
236	            token_count = token_count + 1;
237	
238	        } else if (line[i] == 123) { /* '{' — brace block */
239	            token_starts[token_count] = token_pool_used;
240	            int depth = 1;
241	            tok_putc(line[i]); /* opening brace */
242	            i = i + 1;
243	            while (line[i] && depth > 0) {
244	                if (line[i] == 123) depth = depth + 1;
245	                if (line[i] == 125) depth = depth - 1;
246	                tok_putc(line[i]);
247	                i = i + 1;
248	            }
249	            if (depth != 0) {
250	                uart_puts("error: unterminated brace");
251	                uart_newline();
252	                return -1;
253	            }
254	            tok_end();
255	            token_type[token_count] = TOK_BLOCK;
256	            token_count = token_count + 1;
257	
258	        } else { /* bare word */
259	            token_starts[token_count] = token_pool_used;
260	            while (line[i] && line[i] != 32 && line[i] != 9
261	                   && line[i] != 35) {
262	                tok_putc(line[i]);
263	                i = i + 1;
264	            }
265	            tok_end();
266	            token_type[token_count] = TOK_WORD;
267	            token_count = token_count + 1;
268	        }
269	    }
270	
271	    return token_count;
272	}
273	
274	/* ---- Value type system ---- */
275	
276	/* Type tags */
277	#define VAL_INT 0
278	#define VAL_STR 1
279	#define VAL_REC 2
280	
281	/* Value storage limits */
282	#define MAX_VALS       64
283	
284	/* Parallel arrays for value storage.
285	 * 2D arrays are flattened to 1D to avoid large strides that
286	 * exceed tc24r/as24's lc immediate range (0..127). */
287	int  val_type[MAX_VALS];
288	int  val_int[MAX_VALS];
289	/* 64 * 128 = 8192 */
290	#define VAL_STR_POOL_SIZE 8192
291	/* 64 * 16 = 1024 */
292	#define VAL_REC_POOL_SIZE 1024
293	
294	char val_str_pool[VAL_STR_POOL_SIZE];          /* flat string pool */
295	int  val_rec_fld[VAL_REC_POOL_SIZE];           /* field name value indices */
296	int  val_rec_val[VAL_REC_POOL_SIZE];           /* field value indices */
297	int  val_rec_count[MAX_VALS];
298	int  val_count;
299	
300	/* Index helpers for flat arrays */
301	int vsp(int idx) { return idx * MAX_VAR_VAL; }  /* val_str_pool offset */
302	int vrf(int idx, int f) { return idx * MAX_FIELDS + f; } /* rec field offset */
303	
304	/* Get pointer to a value's string data */
305	char *val_str_ptr(int idx) {
306	    return val_str_pool + vsp(idx);
307	}
308	
309	/* Reset all values (call at start or between scripts) */
310	void val_reset() {
311	    val_count = 0;
312	}
313	
314	/* Allocate a new integer value. Returns index, or -1 on overflow. */
315	int val_new_int(int n) {
316	    if (val_count >= MAX_VALS) return -1;
317	    int idx = val_count;
318	    val_type[idx] = VAL_INT;
319	    val_int[idx] = n;
320	    val_count = val_count + 1;
321	    return idx;
322	}
323	
324	/* Allocate a new string value. Returns index, or -1 on overflow. */
325	int val_new_str(char *s) {
326	    if (val_count >= MAX_VALS) return -1;
327	    int idx = val_count;
328	    val_type[idx] = VAL_STR;
329	    /* Copy string, truncate if needed */
330	    char *dst = val_str_ptr(idx);
331	    int i = 0;
332	    while (s[i] && i < MAX_VAR_VAL - 1) {
333	        dst[i] = s[i];
334	        i = i + 1;
335	    }
336	    dst[i] = 0;
337	    val_count = val_count + 1;
338	    return idx;
339	}
340	
341	/* Allocate a new empty record. Returns index, or -1 on overflow. */
342	int val_new_rec() {
343	    if (val_count >= MAX_VALS) return -1;
344	    int idx = val_count;
345	    val_type[idx] = VAL_REC;
346	    val_rec_count[idx] = 0;
347	    val_count = val_count + 1;
348	    return idx;
349	}
350	
351	/* Set a field in a record. field_name_idx and val_idx are value indices.
352	 * Returns 0 on success, -1 on error. */
353	int val_rec_set(int rec_idx, int field_name_idx, int val_idx) {
354	    if (rec_idx < 0 || rec_idx >= val_count) return -1;
355	    if (val_type[rec_idx] != VAL_REC) return -1;
356	
357	    /* Check if field already exists — update in place */
358	    int fc = val_rec_count[rec_idx];
359	    int i = 0;
360	    while (i < fc) {
361	        if (val_rec_fld[vrf(rec_idx, i)] == field_name_idx) {
362	            val_rec_val[vrf(rec_idx, i)] = val_idx;
363	            return 0;
364	        }
365	        i = i + 1;
366	    }
367	
368	    /* Add new field */
369	    if (fc >= MAX_FIELDS) return -1;
370	    val_rec_fld[vrf(rec_idx, fc)] = field_name_idx;
371	    val_rec_val[vrf(rec_idx, fc)] = val_idx;
372	    val_rec_count[rec_idx] = fc + 1;
373	    return 0;
374	}
375	
376	/* Get a field value from a record by field name string.
377	 * Returns value index, or -1 if not found. */
378	int val_rec_get(int rec_idx, char *field_name) {
379	    if (rec_idx < 0 || rec_idx >= val_count) return -1;
380	    if (val_type[rec_idx] != VAL_REC) return -1;
381	
382	    int fc = val_rec_count[rec_idx];
383	    int i = 0;
384	    while (i < fc) {
385	        int fn_idx = val_rec_fld[vrf(rec_idx, i)];
386	        if (val_type[fn_idx] == VAL_STR && str_eq(val_str_ptr(fn_idx), field_name)) {
387	            return val_rec_val[vrf(rec_idx, i)];
388	        }
389	        i = i + 1;
390	    }
391	    return -1;
392	}
393	
394	/* Check if a record has a field. Returns 1 if exists, 0 if not. */
395	int val_rec_has(int rec_idx, char *field_name) {
396	    return val_rec_get(rec_idx, field_name) >= 0;
397	}
398	
399	/* Format a value as a string into buf. Returns buf. */
400	char *val_to_str(int idx, char *buf) {
401	    if (idx < 0 || idx >= val_count) {
402	        buf[0] = 0;
403	        return buf;
404	    }
405	    if (val_type[idx] == VAL_INT) {
406	        int_to_str(buf, val_int[idx]);
407	    } else if (val_type[idx] == VAL_STR) {
408	        str_copy(buf, val_str_ptr(idx));
409	    } else if (val_type[idx] == VAL_REC) {
410	        /* Debug representation: {field1: val1, field2: val2} */
411	        int p = 0;
412	        buf[p] = 123; /* '{' */
413	        p = p + 1;
414	        int fc = val_rec_count[idx];
415	        int i = 0;
416	        while (i < fc && p < MAX_VAR_VAL - 10) {
417	            if (i > 0) {
418	                buf[p] = 44; /* ',' */
419	                p = p + 1;
420	                buf[p] = 32; /* ' ' */
421	                p = p + 1;
422	            }
423	            /* field name */
424	            int fn_idx = val_rec_fld[vrf(idx, i)];
425	            char tmp[MAX_VAR_VAL];
426	            val_to_str(fn_idx, tmp);
427	            int k = 0;
428	            while (tmp[k] && p < MAX_VAR_VAL - 5) {
429	                buf[p] = tmp[k];
430	                p = p + 1;
431	                k = k + 1;
432	            }
433	            buf[p] = 58; /* ':' */
434	            p = p + 1;
435	            buf[p] = 32; /* ' ' */
436	            p = p + 1;
437	            /* field value */
438	            int fv_idx = val_rec_val[vrf(idx, i)];
439	            val_to_str(fv_idx, tmp);
440	            k = 0;
441	            while (tmp[k] && p < MAX_VAR_VAL - 3) {
442	                buf[p] = tmp[k];
443	                p = p + 1;
444	                k = k + 1;
445	            }
446	            i = i + 1;
447	        }
448	        buf[p] = 125; /* '}' */
449	        p = p + 1;
450	        buf[p] = 0;
451	    } else {
452	        buf[0] = 0;
453	    }
454	    return buf;
455	}
456	
457	/* Compare two values for equality. Returns 1 if equal, 0 if not. */
458	int val_eq(int a, int b) {
459	    if (a < 0 || a >= val_count || b < 0 || b >= val_count) return 0;
460	    if (val_type[a] != val_type[b]) return 0;
461	    if (val_type[a] == VAL_INT) {
462	        return val_int[a] == val_int[b];
463	    }
464	    if (val_type[a] == VAL_STR) {
465	        return str_eq(val_str_ptr(a), val_str_ptr(b));
466	    }
467	    /* Records: equal only if same index */
468	    return a == b;
469	}
470	
471	/* Truthiness: nonzero int = true, nonempty string = true,
472	 * record = true, invalid = false. */
473	int val_is_truthy(int idx) {
474	    if (idx < 0 || idx >= val_count) return 0;
475	    if (val_type[idx] == VAL_INT) {
476	        return val_int[idx] != 0;
477	    }
478	    if (val_type[idx] == VAL_STR) {
479	        char *sp = val_str_ptr(idx);
480	        return sp[0] != 0;
481	    }
482	    /* Records are always truthy */
483	    return 1;
484	}
485	
486	/* ---- Variable environment ---- */
487	
488	/* Flat name pool: var i's name starts at var_name_pool[i * MAX_VAR_NAME] */
489	#define VAR_NAME_POOL_SIZE 2048  /* 64 * 32 = 2048 */
490	char var_name_pool[VAR_NAME_POOL_SIZE];
491	int  var_val[MAX_VARS];   /* value index into value storage */
492	int  var_count;
493	
494	/* Get pointer to variable name */
495	char *var_name(int idx) {
496	    return var_name_pool + idx * MAX_VAR_NAME;
497	}
498	
499	/* Find variable index by name. Returns -1 if not found. */
500	int env_find(char *name) {
501	    int i = 0;
502	    while (i < var_count) {
503	        if (str_eq(var_name(i), name)) return i;
504	        i = i + 1;
505	    }
506	    return -1;
507	}
508	
509	/* Set or update a variable. Returns 0 on success, -1 on overflow. */
510	int env_set(char *name, int val_idx) {
511	    int i = env_find(name);
512	    if (i >= 0) {
513	        var_val[i] = val_idx;
514	        return 0;
515	    }
516	    if (var_count >= MAX_VARS) return -1;
517	    /* Copy name into pool */
518	    char *dst = var_name(var_count);
519	    int k = 0;
520	    while (name[k] && k < MAX_VAR_NAME - 1) {
521	        dst[k] = name[k];
522	        k = k + 1;
523	    }
524	    dst[k] = 0;
525	    var_val[var_count] = val_idx;
526	    var_count = var_count + 1;
527	    return 0;
528	}
529	
530	/* Get value index for a variable. Returns -1 if undefined. */
531	int env_get(char *name) {
532	    int i = env_find(name);
533	    if (i < 0) return -1;
534	    return var_val[i];
535	}
536	
537	/* Check if variable exists. Returns 1 if yes, 0 if no. */
538	int env_has(char *name) {
539	    return env_find(name) >= 0;
540	}
541	
542	/* Remove a variable. Returns 0 on success, -1 if not found. */
543	int env_unset(char *name) {
544	    int i = env_find(name);
545	    if (i < 0) return -1;
546	    /* Shift remaining vars down */
547	    while (i < var_count - 1) {
548	        str_copy(var_name(i), var_name(i + 1));
549	        var_val[i] = var_val[i + 1];
550	        i = i + 1;
551	    }
552	    var_count = var_count - 1;
553	    return 0;
554	}
555	
556	/* Reset environment */
557	void env_reset() {
558	    var_count = 0;
559	}
560	
561	/* ---- Variable substitution ---- */
562	
563	/* Expanded token buffer — tokens after $var substitution */
564	#define EXPAND_POOL_SIZE 2048
565	char expand_pool[EXPAND_POOL_SIZE];
566	int  expand_starts[MAX_TOKENS];
567	int  expand_count;
568	int  expand_pool_used;
569	
570	/* Parse a variable reference from a token string starting at $.
571	 * Writes var name into vname, field name into fname (or empty).
572	 * Returns number of chars consumed (not counting the $). */
573	int parse_var_ref(char *s, char *vname, char *fname) {
574	    int i = 0;
575	    int vi = 0;
576	    /* Read variable name: alphanumeric and underscore */
577	    while (s[i] && s[i] != 46 /* '.' */ && s[i] != 32 && s[i] != 9
578	           && vi < MAX_VAR_NAME - 1) {
579	        vname[vi] = s[i];
580	        vi = vi + 1;
581	        i = i + 1;
582	    }
583	    vname[vi] = 0;
584	    fname[0] = 0;
585	    /* Check for .field */
586	    if (s[i] == 46) { /* '.' */
587	        i = i + 1;
588	        int fi = 0;
589	        while (s[i] && s[i] != 32 && s[i] != 9
590	               && fi < MAX_VAR_NAME - 1) {
591	            fname[fi] = s[i];
592	            fi = fi + 1;
593	            i = i + 1;
594	        }
595	        fname[fi] = 0;
596	    }
597	    return i;
598	}
599	
600	/* Runtime error flag — set to 1 on error */
601	int runtime_error;
602	
603	/* Expand variables in tokens. Replaces token_pool/token_starts with
604	 * expanded versions in expand_pool/expand_starts.
605	 * Returns 0 on success, -1 on error (e.g. undefined variable). */
606	int expand_variables() {
607	    expand_count = 0;
608	    expand_pool_used = 0;
609	    runtime_error = 0;
610	    int t = 0;
611	    while (t < token_count) {
612	        char *tok = token_str(t);
613	        int ttype = token_type[t];
614	        expand_starts[expand_count] = expand_pool_used;
615	
616	        if (ttype == TOK_BLOCK) {
617	            /* Blocks are NOT expanded — they are deferred */
618	            int k = 0;
619	            while (tok[k] && expand_pool_used < EXPAND_POOL_SIZE - 1) {
620	                expand_pool[expand_pool_used] = tok[k];
621	                expand_pool_used = expand_pool_used + 1;
622	                k = k + 1;
623	            }
624	        } else if (tok[0] == 36) { /* '$' — entire token is a variable ref */
625	            char vname[MAX_VAR_NAME];
626	            char fname[MAX_VAR_NAME];
627	            parse_var_ref(tok + 1, vname, fname);
628	
629	            int vi = env_get(vname);
630	            if (vi < 0) {
631	                uart_puts("error: undefined variable: ");
632	                uart_puts(vname);
633	                uart_newline();
634	                runtime_error = 1;
635	                return -1;
636	            }
637	
638	            if (fname[0]) {
639	                /* $var.field — record field access */
640	                if (val_type[vi] != VAL_REC) {
641	                    uart_puts("error: not a record: ");
642	                    uart_puts(vname);
643	                    uart_newline();
644	                    runtime_error = 1;
645	                    return -1;
646	                }
647	                int fvi = val_rec_get(vi, fname);
648	                if (fvi < 0) {
649	                    uart_puts("error: no field '");
650	                    uart_puts(fname);
651	                    uart_puts("' in ");
652	                    uart_puts(vname);
653	                    uart_newline();
654	                    runtime_error = 1;
655	                    return -1;
656	                }
657	                /* Format field value as string */
658	                char tmp[MAX_VAR_VAL];
659	                val_to_str(fvi, tmp);
660	                int k = 0;
661	                while (tmp[k] && expand_pool_used < EXPAND_POOL_SIZE - 1) {
662	                    expand_pool[expand_pool_used] = tmp[k];
663	                    expand_pool_used = expand_pool_used + 1;
664	                    k = k + 1;
665	                }
666	            } else {
667	                /* $var — format value as string */
668	                char tmp[MAX_VAR_VAL];
669	                val_to_str(vi, tmp);
670	                int k = 0;
671	                while (tmp[k] && expand_pool_used < EXPAND_POOL_SIZE - 1) {
672	                    expand_pool[expand_pool_used] = tmp[k];
673	                    expand_pool_used = expand_pool_used + 1;
674	                    k = k + 1;
675	                }
676	            }
677	        } else {
678	            /* Plain token — copy as-is */
679	            int k = 0;
680	            while (tok[k] && expand_pool_used < EXPAND_POOL_SIZE - 1) {
681	                expand_pool[expand_pool_used] = tok[k];
682	                expand_pool_used = expand_pool_used + 1;
683	                k = k + 1;
684	            }
685	        }
686	        /* Null-terminate expanded token */
687	        if (expand_pool_used < EXPAND_POOL_SIZE) {
688	            expand_pool[expand_pool_used] = 0;
689	            expand_pool_used = expand_pool_used + 1;
690	        }
691	        expand_count = expand_count + 1;
692	        t = t + 1;
693	    }
694	    return 0;
695	}
696	
697	/* Get pointer to expanded token string */
698	char *exp_str(int idx) {
699	    return expand_pool + expand_starts[idx];
700	}
701	
702	/* ---- Helpers for value creation from token strings ---- */
703	
704	/* Check if a string looks like an integer (optional minus, then digits) */
705	int is_int_str(char *s) {
706	    int i = 0;
707	    if (s[0] == 45) i = 1; /* '-' */
708	    if (s[i] == 0) return 0; /* empty or just "-" */
709	    while (s[i]) {
710	        if (s[i] < 48 || s[i] > 57) return 0;
711	        i = i + 1;
712	    }
713	    return 1;
714	}
715	
716	/* Create a value from a string — auto-detect int vs string */
717	int val_from_str(char *s) {
718	    if (is_int_str(s)) {
719	        return val_new_int(str_to_int(s));
720	    }
721	    return val_new_str(s);
722	}
723	
724	/* ---- Input buffer ---- */
725	
726	char line_buf[MAX_LINE_LEN];
727	
728	int read_line(char *buf, int max) {
729	    int i = 0;
730	    int brace_depth = 0;
731	    while (i < max - 1) {
732	        int ch = uart_getc();
733	        if (ch == 4) { /* Ctrl-D: EOF */
734	            if (i == 0) return -1;
735	            break;
736	        }
737	        if (ch == 10 || ch == 13) { /* newline */
738	            if (brace_depth <= 0) break;
739	            /* Inside braces: treat newline as newline in block */
740	            buf[i] = 10;
741	            i = i + 1;
742	            continue;
743	        }
744	        buf[i] = ch;
745	        i = i + 1;
746	        if (ch == 123) brace_depth = brace_depth + 1; /* '{' */
747	        if (ch == 125) brace_depth = brace_depth - 1; /* '}' */
748	    }
749	    buf[i] = 0;
750	    return i;
751	}
752	
753	/* ---- Halt ---- */
754	
755	void halt() {
756	    asm("_user_halt:");
757	    asm("bra _user_halt");
758	}
759	
760	/* ---- Main ---- */
761	
762	char *tok_type_name(int t) {
763	    if (t == TOK_WORD)   return "WORD";
764	    if (t == TOK_QUOTED) return "QUOTED";
765	    if (t == TOK_BLOCK)  return "BLOCK";
766	    return "?";
767	}
768	
769	char val_fmt_buf[MAX_VAR_VAL];
770	
771	void val_print(int idx) {
772	    val_to_str(idx, val_fmt_buf);
773	    uart_puts(val_fmt_buf);
774	}
775	
776	/* ---- exists? helper (checks without runtime error) ---- */
777	
778	/* Check if $var or $var.field reference is valid.
779	 * tok is the raw token including the $ prefix.
780	 * Returns 1 if present, 0 if not. Never errors. */
781	int check_exists(char *tok) {
782	    if (tok[0] != 36) return 0; /* must start with $ */
783	    char vname[MAX_VAR_NAME];
784	    char fname[MAX_VAR_NAME];
785	    parse_var_ref(tok + 1, vname, fname);
786	
787	    int vi = env_get(vname);
788	    if (vi < 0) return 0; /* variable not defined */
789	    if (fname[0] == 0) return 1; /* just $var, exists */
790	    /* $var.field — check record */
791	    if (val_type[vi] != VAL_REC) return 0;
792	    return val_rec_has(vi, fname);
793	}
794	
795	int main() {
796	    uart_puts("sws 0.1");
797	    uart_newline();
798	
799	    val_reset();
800	    env_reset();
801	
802	    while (1) {
803	        uart_puts("> ");
804	        int len = read_line(line_buf, MAX_LINE_LEN);
805	        if (len < 0) break; /* EOF */
806	        if (len == 0) continue; /* empty line */
807	
808	        int count = tokenize_line(line_buf);
809	        if (count < 0) continue; /* syntax error already reported */
810	        if (count == 0) continue; /* blank or comment-only */
811	
812	        /* Built-in: _valtest — exercise value type system */
813	        if (str_eq(token_str(0), "_valtest")) {
814	            val_reset();
815	
816	            /* Integer values */
817	            int v0 = val_new_int(42);
818	            int v1 = val_new_int(0);
819	            int v2 = val_new_int(-7);
820	
821	            /* String values */
822	            int v3 = val_new_str("hello");
823	            int v4 = val_new_str("");
824	
825	            /* Record with fields */
826	            int v5 = val_new_rec();
827	            int fn_status = val_new_str("status");
828	            int fv_status = val_new_int(0);
829	            int fn_output = val_new_str("output");
830	            int fv_output = val_new_str("ok");
831	            val_rec_set(v5, fn_status, fv_status);
832	            val_rec_set(v5, fn_output, fv_output);
833	
834	            /* Print each value */
835	            uart_puts("int:"); val_print(v0); uart_newline();
836	            uart_puts("zero:"); val_print(v1); uart_newline();
837	            uart_puts("neg:"); val_print(v2); uart_newline();
838	            uart_puts("str:"); val_print(v3); uart_newline();
839	            uart_puts("empty:"); val_print(v4); uart_newline();
840	            uart_puts("rec:"); val_print(v5); uart_newline();
841	
842	            /* Equality tests */
843	            int v6 = val_new_int(42);
844	            uart_puts("eq:"); uart_putint(val_eq(v0, v6)); uart_newline();
845	            uart_puts("ne:"); uart_putint(val_eq(v0, v1)); uart_newline();
846	
847	            /* Truthiness */
848	            uart_puts("truthy42:"); uart_putint(val_is_truthy(v0)); uart_newline();
849	            uart_puts("truthy0:"); uart_putint(val_is_truthy(v1)); uart_newline();
850	            uart_puts("truthyS:"); uart_putint(val_is_truthy(v3)); uart_newline();
851	            uart_puts("truthyE:"); uart_putint(val_is_truthy(v4)); uart_newline();
852	            uart_puts("truthyR:"); uart_putint(val_is_truthy(v5)); uart_newline();
853	
854	            /* Record field access */
855	            int got = val_rec_get(v5, "status");
856	            uart_puts("field:"); val_print(got); uart_newline();
857	            uart_puts("has:"); uart_putint(val_rec_has(v5, "output")); uart_newline();
858	            uart_puts("miss:"); uart_putint(val_rec_has(v5, "nope")); uart_newline();
859	
860	            uart_puts("vals:"); uart_putint(val_count); uart_newline();
861	            continue;
862	        }
863	
864	        /* exists? — must check BEFORE variable expansion (to avoid error on missing vars) */
865	        if (str_eq(token_str(0), "exists?")) {
866	            if (count < 2) {
867	                uart_puts("error: exists? requires an argument");
868	                uart_newline();
869	                continue;
870	            }
871	            uart_putint(check_exists(token_str(1)));
872	            uart_newline();
873	            continue;
874	        }
875	
876	        /* Expand variables in tokens */
877	        if (expand_variables() < 0) continue; /* runtime error already reported */
878	
879	        /* --- Command dispatch --- */
880	
881	        /* set name value */
882	        if (str_eq(exp_str(0), "set")) {
883	            if (expand_count < 3) {
884	                uart_puts("error: set requires name and value");
885	                uart_newline();
886	                continue;
887	            }
888	            char *name = exp_str(1);
889	            char *val_s = exp_str(2);
890	            int vi = val_from_str(val_s);
891	            if (vi < 0) {
892	                uart_puts("error: value overflow");
893	                uart_newline();
894	                continue;
895	            }
896	            env_set(name, vi);
897	            continue;
898	        }
899	
900	        /* echo args... */
901	        if (str_eq(exp_str(0), "echo")) {
902	            int j = 1;
903	            while (j < expand_count) {
904	                if (j > 1) uart_putc(32); /* space */
905	                uart_puts(exp_str(j));
906	                j = j + 1;
907	            }
908	            uart_newline();
909	            continue;
910	        }
911	
912	        /* Debug: echo tokens (for unrecognized commands) */
913	        int j = 0;
914	        while (j < expand_count) {
915	            uart_puts("[");
916	            uart_puts(tok_type_name(token_type[j]));
917	            uart_puts("|");
918	            uart_puts(exp_str(j));
919	            uart_puts("]");
920	            if (j < expand_count - 1) uart_putc(32); /* space */
921	            j = j + 1;
922	        }
923	        uart_newline();
924	    }
925	
926	    halt();
927	    return 0;
928	}
