/* test_fnptr.c -- validate function pointer support in tc24r
 * Tests the patterns needed for sws command dispatch tables.
 */

#define UART_DATA   0xFF0100
#define UART_STATUS 0xFF0101

void uart_putc(int ch) {
    int tries = 50000;
    while ((*(char *)UART_STATUS & 0x80) && tries > 0) {
        tries = tries - 1;
    }
    *(char *)UART_DATA = ch;
}

void uart_puts(char *s) {
    while (*s) {
        uart_putc(*s);
        s = s + 1;
    }
}

void uart_putint(int n) {
    if (n < 0) {
        uart_putc(45);
        n = 0 - n;
    }
    if (n == 0) {
        uart_putc(48);
        return;
    }
    char buf[12];
    int i = 0;
    while (n > 0) {
        buf[i] = 48 + n % 10;
        n = n / 10;
        i = i + 1;
    }
    while (i > 0) {
        i = i - 1;
        uart_putc(buf[i]);
    }
}

void uart_newline() {
    uart_putc(10);
}

void halt() {
    asm("_user_halt:");
    asm("bra _user_halt");
}

/* --- Test 1: Basic function pointer variable --- */

int add(int a, int b) {
    return a + b;
}

int mul(int a, int b) {
    return a * b;
}

/* --- Test 2: Array of function pointers (command dispatch pattern) --- */

#define MAX_HANDLERS 4

/* Handler signature: takes no args, returns int */
int handler_alpha() {
    uart_puts("alpha");
    uart_newline();
    return 0;
}

int handler_beta() {
    uart_puts("beta");
    uart_newline();
    return 1;
}

int handler_gamma() {
    uart_puts("gamma");
    uart_newline();
    return 2;
}

/* --- Test 3: Function pointer as parameter --- */

int apply(int (*f)(int, int), int x, int y) {
    return f(x, y);
}

/* --- Main --- */

int main() {
    uart_puts("fnptr test");
    uart_newline();

    /* Test 1: function pointer variable */
    int (*fp)(int, int);
    fp = add;
    int r = fp(3, 4);
    uart_puts("t1:"); uart_putint(r); uart_newline(); /* expect 7 */

    fp = mul;
    r = fp(3, 4);
    uart_puts("t2:"); uart_putint(r); uart_newline(); /* expect 12 */

    /* Test 2: array of function pointers */
    int (*table[MAX_HANDLERS])();
    table[0] = handler_alpha;
    table[1] = handler_beta;
    table[2] = handler_gamma;

    uart_puts("t3:");
    int rv = table[0](); /* expect "alpha", rv=0 */
    uart_putint(rv); uart_newline();

    uart_puts("t4:");
    rv = table[1](); /* expect "beta", rv=1 */
    uart_putint(rv); uart_newline();

    uart_puts("t5:");
    rv = table[2](); /* expect "gamma", rv=2 */
    uart_putint(rv); uart_newline();

    /* Test 3: function pointer as parameter */
    r = apply(add, 10, 20);
    uart_puts("t6:"); uart_putint(r); uart_newline(); /* expect 30 */

    r = apply(mul, 5, 6);
    uart_puts("t7:"); uart_putint(r); uart_newline(); /* expect 30 */

    /* Test 4: dispatch by index (the actual sws pattern) */
    int idx = 2;
    rv = table[idx](); /* expect "gamma", rv=2 */
    uart_puts("t8:"); uart_putint(rv); uart_newline();

    uart_puts("PASS");
    uart_newline();

    halt();
    return 0;
